patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 24a166906f1f..059df0c9b79a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1236,19 +1236,34 @@ static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // Rounding is done by adding -1 if the dividend (X) is negative and has any
   // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
   // sext (icmp ugt (X & (DivC - 1)), SMIN)
+  // Alternative for div-by-2: sext (icmp eq (X & (SMin | 1)), (SMin | 1))
+  // Note: For div-by-2 only, (X & Mask) == Mask is equivalent to (X & Mask) >u SMin
+  // because Mask = SMin | 1, so the only value >u SMin and <= Mask is Mask itself.
   const APInt *MaskC;
+  Value *CmpRHS;
   ICmpInst::Predicate Pred;
   if (!match(Add.getOperand(1),
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_Value(CmpRHS)))))
+    return nullptr;
+
+  // CmpRHS must be a constant
+  const APInt *CmpRHSConst;
+  if (!match(CmpRHS, m_APInt(CmpRHSConst)))
     return nullptr;

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
+
+  // Check for either: icmp ugt (X & Mask, SMin) or icmp eq (X & Mask, Mask) (div-by-2 only)
+  bool ValidPattern = (Pred == ICmpInst::ICMP_UGT && *CmpRHSConst == SMin) ||
+                      (Pred == ICmpInst::ICMP_EQ && *CmpRHSConst == *MaskC && *DivC == 2);
+  if (!ValidPattern)
+    return nullptr;
+
   if (*MaskC != (SMin | (*DivC - 1)))
     return nullptr;

-  // (X / DivC) + sext ((X & (SMin | (DivC - 1)) >u SMin) --> X >>s log2(DivC)
+  // (X / DivC) + sext ((X & (SMin | (DivC - 1))) >u SMin or == Mask) --> X >>s log2(DivC)
   return BinaryOperator::CreateAShr(
       X, ConstantInt::get(Add.getType(), DivC->exactLogBase2()));
 }

